// Datos de proyectos activos leídos de SeguimientoProyectos/*.xlsx
// Para actualizar: python analizar_proyectos.py > proyectos.json
// y reemplazar el array 'projects' con el nuevo JSON
//
// ⚠️ REEMPLAZA estos datos de ejemplo con los de tu proyecto real

const projects = [{"archivo":"ClienteABC-MigracionPlataforma.xlsx","proyecto":"ClienteABC - Migración de Plataforma","cliente":"ClienteABC","pm":"Ana García","inicio":"01/05/2026","cierre":"30/07/2026","tasks":[{"id":"T001","fase":"Inicio","categoria":"Inicio","tarea":"Firma de orden de compra","responsable":"Ana García","fecha_inicio":"01/05/2026","fecha_fin":"05/05/2026","prioridad":"Baja","estado":"Completado","avance":"100%","notas":""},{"id":"T002","fase":"Inicio","categoria":"Inicio","tarea":"Firma del alcance","responsable":"Ana García","fecha_inicio":"01/05/2026","fecha_fin":"05/05/2026","prioridad":"Baja","estado":"Completado","avance":"100%","notas":""},{"id":"T003","fase":"Diseño","categoria":"Diseño","tarea":"Diseño del flujo","responsable":"Carlos López","fecha_inicio":"06/05/2026","fecha_fin":"19/05/2026","prioridad":"Media","estado":"Completado","avance":"100%","notas":""},{"id":"T004","fase":"Diseño","categoria":"Diseño","tarea":"Diseño de la arquitectura","responsable":"Carlos López","fecha_inicio":"06/05/2026","fecha_fin":"19/05/2026","prioridad":"Media","estado":"Completado","avance":"100%","notas":""},{"id":"T005","fase":"Diseño","categoria":"Diseño","tarea":"LLD - Low Level Design","responsable":"Carlos López","fecha_inicio":"06/05/2026","fecha_fin":"19/05/2026","prioridad":"Media","estado":"Completado","avance":"100%","notas":""},{"id":"T006","fase":"Desarrollo","categoria":"Desarrollo","tarea":"Desarrollo de flujos","responsable":"Luis Martínez","fecha_inicio":"20/05/2026","fecha_fin":"28/05/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T007","fase":"Desarrollo","categoria":"Desarrollo","tarea":"Desarrollo de versiones de SW","responsable":"Carlos López","fecha_inicio":"20/05/2026","fecha_fin":"28/05/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T008","fase":"Implementación","categoria":"Implementación","tarea":"Entrega de hardware","responsable":"PM Cliente","fecha_inicio":"29/05/2026","fecha_fin":"15/06/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T009","fase":"Implementación","categoria":"Implementación","tarea":"Pruebas básicas de integración","responsable":"María Rodríguez / PM Cliente","fecha_inicio":"29/05/2026","fecha_fin":"15/06/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T010","fase":"Implementación","categoria":"Implementación","tarea":"Instalación de software","responsable":"Carlos López","fecha_inicio":"29/05/2026","fecha_fin":"15/06/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T011","fase":"Implementación","categoria":"Implementación","tarea":"Integración inicial","responsable":"Carlos López","fecha_inicio":"29/05/2026","fecha_fin":"15/06/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T012","fase":"Implementación","categoria":"Implementación","tarea":"Configuración de solución","responsable":"María Rodríguez","fecha_inicio":"29/05/2026","fecha_fin":"15/06/2026","prioridad":"Alta","estado":"Completado","avance":"100%","notas":""},{"id":"T013","fase":"Pruebas","categoria":"Pruebas","tarea":"Pruebas de integración","responsable":"María Rodríguez","fecha_inicio":"16/06/2026","fecha_fin":"12/07/2026","prioridad":"Alta","estado":"En progreso","avance":"20%","notas":""},{"id":"T014","fase":"Aceptación","categoria":"Aceptación","tarea":"Aceptación UAT","responsable":"PM Cliente","fecha_inicio":"13/07/2026","fecha_fin":"16/07/2026","prioridad":"Alta","estado":"Pendiente","avance":"0%","notas":""},{"id":"T015","fase":"Puesta en Producción","categoria":"Puesta en Producción","tarea":"Agendamiento de la puesta en producción","responsable":"PM Cliente","fecha_inicio":"17/07/2026","fecha_fin":"25/07/2026","prioridad":"Media","estado":"Pendiente","avance":"0%","notas":""},{"id":"T016","fase":"Puesta en Producción","categoria":"Puesta en Producción","tarea":"Ventana de puesta en producción","responsable":"María Rodríguez","fecha_inicio":"17/07/2026","fecha_fin":"25/07/2026","prioridad":"Media","estado":"Pendiente","avance":"0%","notas":""},{"id":"T017","fase":"Fin del Proyecto","categoria":"Fin del Proyecto","tarea":"Firma del documento FAC","responsable":"Ana García / PM Cliente","fecha_inicio":"26/07/2026","fecha_fin":"30/07/2026","prioridad":"Baja","estado":"Pendiente","avance":"0%","notas":""}],"contactos_internos":[{"nombre":"Ana García","rol":"SDM","email":"equipo@tuempresa.com"}],"contactos_cliente":[{"nombre":"Contacto Cliente","rol":"PM","email":"pm@clienteabc.com"}]}];

return projects.map(p => ({ json: p }));

// Construye el prompt con los datos del proyecto
// Nota: se expone 'prompt' como campo top-level para que Basic LLM Chain lea $json.prompt
const p = $input.first().json;
const today = new Date().toLocaleDateString('es-ES');

const tareasTexto = p.tasks.map(t =>
  `[${t.id}] ${t.tarea} | Fase: ${t.fase} | Responsable: ${t.responsable} | Estado: ${t.estado} | Avance: ${t.avance} | Fecha límite: ${t.fecha_fin} | Prioridad: ${t.prioridad}`
).join('\n');

const userPrompt = `Analiza los siguientes datos del proyecto y genera el reporte semanal.

FECHA DE HOY: ${today}
PROYECTO: ${p.proyecto}
CLIENTE: ${p.cliente}
PM: ${p.pm}
INICIO: ${p.inicio} | CIERRE ESTIMADO: ${p.cierre}

TAREAS:\n${tareasTexto}

Genera una respuesta JSON con esta estructura exacta:
{
  "resumen_global": {
    "avance_porcentaje": (número 0-100, promedio de avances),
    "tareas_completadas": (número),
    "total_tareas": (número),
    "riesgo": ("Sin riesgo" o "Riesgo medio" o "Riesgo alto"),
    "justificacion_riesgo": "(una línea explicando el nivel de riesgo)"
  },
  "alertas_criticas": [
    {"tarea": "", "responsable": "", "dias_retraso": 0, "bloqueo": ""}
  ],
  "reporte_interno": {
    "asunto": "[Reporte Interno] ${p.proyecto} - Semana ${today}",
    "cuerpo": "(reporte detallado con semáforos por tarea 🟢🟡🔴, % de avance global, alertas críticas con nombres y responsables, nivel de riesgo con justificación, tono directo y profesional)"
  },
  "reporte_cliente": {
    "asunto": "Avance Semanal - ${p.proyecto} - ${today}",
    "cuerpo": "(reporte ejecutivo profesional: resumen de 2-3 líneas de lo logrado esta semana, hitos completados, próximos hitos, estado general En tiempo/Con retraso leve/Requiere atención. Sin detalles internos ni nombres de responsables. Tono profesional orientado a resultados)"
  }
}`;

const openai_body = {
  model: 'gpt-4o',
  temperature: 0.3,
  messages: [
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: { ...p, prompt: userPrompt, openai_body } }];

// Parsea la respuesta del LLM y prepara los datos para los emails
const openaiResponse = $input.first().json;
const projectData = $('Construir Prompt').first().json;

// Basic LLM Chain devuelve en .text; AI Agent devuelve en .output
let content = openaiResponse.text || openaiResponse.output || '';

// Limpiar markdown code blocks si el modelo los agrega
content = content.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/, '').trim();

const analysis = JSON.parse(content);

const emailsInternos = (projectData.contactos_internos || [])
  .map(c => c.email)
  .filter(e => e && e.includes('@'))
  .join(',');

const emailsCliente = (projectData.contactos_cliente || [])
  .map(c => c.email)
  .filter(e => e && e.includes('@'))
  .join(',');

return [{
  json: {
    proyecto:              projectData.proyecto,
    cliente:               projectData.cliente,
    pm:                    projectData.pm,
    resumen_global:        analysis.resumen_global,
    alertas_criticas:      analysis.alertas_criticas || [],
    emails_internos:       emailsInternos,
    emails_cliente:        emailsCliente,
    asunto_interno:        analysis.reporte_interno.asunto,
    cuerpo_interno:        analysis.reporte_interno.cuerpo,
    asunto_cliente:        analysis.reporte_cliente.asunto,
    cuerpo_cliente:        analysis.reporte_cliente.cuerpo,
    tiene_emails_internos: emailsInternos.length > 0,
    tiene_emails_cliente:  emailsCliente.length > 0
  }
}];
